import React, { useEffect, useMemo, useState } from 'react';
import axios from 'axios';
import { MapPin } from 'lucide-react';
import { formatTimeAgo } from '../lib/time';

export default function AlertsPage({ apiBaseUrl, auth, onOpenLive }) {
  const [alerts, setAlerts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const axiosClient = useMemo(() => {
    const instance = axios.create({ baseURL: apiBaseUrl });
    if (auth?.token) {
      instance.interceptors.request.use((config) => {
        config.headers = config.headers || {};
        config.headers.Authorization = `Bearer ${auth.token}`;
        return config;
      });
    }
    return instance;
  }, [apiBaseUrl, auth?.token]);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError('');
    axiosClient
      .get('/api/reports/active')
      .then((res) => {
        const data = res.data || [];
        const filtered = data.filter((r) => {
          const level = String(r.waterLevel || r.intensity || '').toLowerCase();
          return level === 'high' || level === 'medium' || level === 'vehicle_risk' || level === 'knee';
        });
        if (!cancelled) setAlerts(filtered);
      })
      .catch((e) => {
        if (!cancelled) setError(e?.response?.data?.msg || 'Failed to load alerts');
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });

    return () => {
      cancelled = true;
    };
  }, [axiosClient]);

  return (
    <div className="mx-auto w-full max-w-5xl p-4">
      <div className="flex items-center justify-between gap-3">
        <div>
          <div className="text-xl font-bold tracking-tight text-slate-100">Alerts</div>
          <div className="mt-1 text-sm text-slate-400">Medium/High reports (last 24 hours)</div>
        </div>
        <button
          type="button"
          onClick={() => onOpenLive?.()}
          className="inline-flex items-center gap-2 rounded-2xl bg-sky-500 px-4 py-2 text-sm font-semibold text-slate-950 hover:bg-sky-400"
        >
          <MapPin size={16} />
          Open Live Map
        </button>
      </div>

      <div className="mt-4 rounded-3xl border border-white/10 bg-slate-950/60 p-4 shadow-soft backdrop-blur">
        {loading ? (
          <div className="p-4 text-sm text-slate-300">Loading…</div>
        ) : error ? (
          <div className="p-4 text-sm text-red-200">{error}</div>
        ) : alerts.length === 0 ? (
          <div className="p-4 text-sm text-slate-300">No alerts right now.</div>
        ) : (
          <div className="grid gap-3">
            {alerts.map((r) => {
              const level = r.waterLevel || r.intensity || 'Alert';
              const ts = r.createdAt || r.timestamp || r.time;
              return (
                <div
                  key={r._id || `${r.lat}-${r.lng}-${ts}`}
                  className="rounded-2xl border border-white/10 bg-black/20 p-4"
                >
                  <div className="flex items-center justify-between gap-2">
                    <div className="text-sm font-semibold text-slate-100">{level}</div>
                    <div className="text-xs text-slate-400">{formatTimeAgo(ts)}</div>
                  </div>
                  {r.address ? <div className="mt-1 text-xs text-slate-400">{r.address}</div> : null}
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}
